import { Page, PageSection, SectionTemplate, Translation, MediaFile, User, AdminSettings } from './types';

const API_BASE = '/api/admin';

// Pages API
export const pagesApi = {
  async getAll(): Promise<Page[]> {
    const response = await fetch(`${API_BASE}/pages`);
    return response.json();
  },

  async getById(id: string): Promise<Page> {
    const response = await fetch(`${API_BASE}/pages/${id}`);
    return response.json();
  },

  async create(page: Omit<Page, 'id' | 'createdAt' | 'updatedAt'>): Promise<Page> {
    const response = await fetch(`${API_BASE}/pages`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(page),
    });
    return response.json();
  },

  async update(id: string, page: Partial<Page>): Promise<Page> {
    const response = await fetch(`${API_BASE}/pages/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(page),
    });
    return response.json();
  },

  async delete(id: string): Promise<void> {
    await fetch(`${API_BASE}/pages/${id}`, {
      method: 'DELETE',
    });
  },

  async updateSections(pageId: string, sections: PageSection[]): Promise<void> {
    await fetch(`${API_BASE}/pages/${pageId}/sections`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sections }),
    });
  },
};

