// Translations API
export const translationsApi = {
  async getAll(language?: string): Promise<Translation[]> {
    const url = language ? `${API_BASE}/translations?language=${language}` : `${API_BASE}/translations`;
    const response = await fetch(url);
    return response.json();
  },

  async update(translations: Translation[]): Promise<void> {
    await fetch(`${API_BASE}/translations`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ translations }),
    });
  },

  async exportTranslations(language: string): Promise<Record<string, unknown>> {
    const response = await fetch(`${API_BASE}/translations/export?language=${language}`);
    return response.json();
  },

  async importTranslations(language: string, data: Record<string, unknown>): Promise<void> {
    await fetch(`${API_BASE}/translations/import`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ language, data }),
    });
  },
};

// Media API
export const mediaApi = {
  async getAll(): Promise<MediaFile[]> {
    const response = await fetch(`${API_BASE}/media`);
    return response.json();
  },

  async upload(file: File, altText?: string): Promise<MediaFile> {
    const formData = new FormData();
    formData.append('file', file);
    if (altText) formData.append('altText', altText);

    const response = await fetch(`${API_BASE}/media`, {
      method: 'POST',
      body: formData,
    });
    return response.json();
  },

  async update(id: string, data: { altText?: string }): Promise<MediaFile> {
    const response = await fetch(`${API_BASE}/media/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    return response.json();
  },

  async delete(id: string): Promise<void> {
    await fetch(`${API_BASE}/media/${id}`, {
      method: 'DELETE',
    });
  },
};

