// Analytics API
export const analyticsApi = {
  async getDashboardStats(): Promise<{
    totalPages: number;
    publishedPages: number;
    draftPages: number;
    totalSections: number;
    totalMedia: number;
    totalUsers: number;
  }> {
    const response = await fetch(`${API_BASE}/analytics/dashboard`);
    return response.json();
  },

  async getPageViews(pageId?: string, days = 30): Promise<{
    date: string;
    views: number;
  }[]> {
    const url = pageId 
      ? `${API_BASE}/analytics/page-views?pageId=${pageId}&days=${days}`
      : `${API_BASE}/analytics/page-views?days=${days}`;
    const response = await fetch(url);
    return response.json();
  },
};